      input.description,
      input.completed,
      input.dueDate,
      input.priority,
    ],
  );

  return mapTodoRow(result.rows[0]);
}

export async function updateTodo(
  todoId: string,
  userId: string,
  payload: unknown,
): Promise<TodoRecord> {
  const updates = normalizeUpdateTodoInput(payload);
  const setClauses: string[] = [];
  const values: unknown[] = [todoId, userId];

  if ("title" in updates) {
    setClauses.push(`title = $${values.length + 1}`);
    values.push(updates.title);
  }

  if ("description" in updates) {
    setClauses.push(`description = $${values.length + 1}`);
    values.push(updates.description);
  }

  if ("completed" in updates) {
    setClauses.push(`completed = $${values.length + 1}`);
    values.push(updates.completed);
  }

  if ("dueDate" in updates) {
    setClauses.push(`due_date = $${values.length + 1}`);
    values.push(updates.dueDate);
  }

  if ("priority" in updates) {
    setClauses.push(`priority = $${values.length + 1}`);
    values.push(updates.priority);
  }

  setClauses.push("updated_at = CURRENT_TIMESTAMP");

  const result = await query<TodoRow>(
    `
      UPDATE todos
      SET ${setClauses.join(", ")}
      WHERE id = $1
        AND user_id = $2
      RETURNING
        id,
        user_id,
        title,
        description,
        completed,
        due_date,
        priority,
        created_at,
        updated_at
    `,
    values,
  );

  const todo = result.rows[0];

  if (!todo) {
    throw new TodoNotFoundError("Todo not found.");
  }

  return mapTodoRow(todo);
}

export async function deleteTodo(
  todoId: string,
  userId: string,
): Promise<void> {
  const result = await query(
    `
      DELETE FROM todos
      WHERE id = $1
        AND user_id = $2
    `,
    [todoId, userId],
  );

  if (result.rowCount === 0) {
    throw new TodoNotFoundError("Todo not found.");
  }
}

